using System;

namespace Ink.FontAwesome;

[Flags]
internal enum FaceSet
{
    None = 0,
    ClassicRegular = 1 << 0,
    ClassicSolid = 1 << 1,
    ClassicLight = 1 << 2,
    ClassicThin = 1 << 3,
    DuotoneRegular = 1 << 4,
    DuotoneSolid = 1 << 5,
    DuotoneLight = 1 << 6,
    DuotoneThin = 1 << 7,
    SharpRegular = 1 << 8,
    SharpSolid = 1 << 9,
    SharpLight = 1 << 10,
    SharpThin = 1 << 11,
    SharpDuotoneRegular = 1 << 12,
    SharpDuotoneSolid = 1 << 13,
    SharpDuotoneLight = 1 << 14,
    SharpDuotoneThin = 1 << 15,
    Brands = 1 << 16,
}

/// <summary>
/// Generated metadata lookup for Font Awesome icons.
/// </summary>
internal static class FontAwesomeMetadata
{
    public static string GetGlyph(Icon icon)
        => char.ConvertFromUtf32(GetCodePoint(icon));

    public static Face ResolveFace(Icon icon, Face requestedFace)
    {
        var supportedFaces = GetSupportedFaces(icon);
        var requestedFlag = ToFaceSet(requestedFace);

        if ((supportedFaces & requestedFlag) != 0)
            return requestedFace;

        if ((supportedFaces & FaceSet.ClassicSolid) != 0)
            return Face.ClassicSolid;

        if ((supportedFaces & FaceSet.ClassicRegular) != 0)
            return Face.ClassicRegular;

        if ((supportedFaces & FaceSet.ClassicLight) != 0)
            return Face.ClassicLight;

        if ((supportedFaces & FaceSet.ClassicThin) != 0)
            return Face.ClassicThin;

        if ((supportedFaces & FaceSet.DuotoneSolid) != 0)
            return Face.DuotoneSolid;

        if ((supportedFaces & FaceSet.DuotoneRegular) != 0)
            return Face.DuotoneRegular;

        if ((supportedFaces & FaceSet.DuotoneLight) != 0)
            return Face.DuotoneLight;

        if ((supportedFaces & FaceSet.DuotoneThin) != 0)
            return Face.DuotoneThin;

        if ((supportedFaces & FaceSet.SharpSolid) != 0)
            return Face.SharpSolid;

        if ((supportedFaces & FaceSet.SharpRegular) != 0)
            return Face.SharpRegular;

        if ((supportedFaces & FaceSet.SharpLight) != 0)
            return Face.SharpLight;

        if ((supportedFaces & FaceSet.SharpThin) != 0)
            return Face.SharpThin;

        if ((supportedFaces & FaceSet.SharpDuotoneSolid) != 0)
            return Face.SharpDuotoneSolid;

        if ((supportedFaces & FaceSet.SharpDuotoneRegular) != 0)
            return Face.SharpDuotoneRegular;

        if ((supportedFaces & FaceSet.SharpDuotoneLight) != 0)
            return Face.SharpDuotoneLight;

        if ((supportedFaces & FaceSet.SharpDuotoneThin) != 0)
            return Face.SharpDuotoneThin;

        if ((supportedFaces & FaceSet.Brands) != 0)
            return Face.Brands;

        throw new ArgumentOutOfRangeException(nameof(icon), icon, "The icon has no supported faces.");
    }

